"use strict";(self.webpackChunkwasmcloud_com=self.webpackChunkwasmcloud_com||[]).push([["67985"],{10002:function(e,t,a){a.d(t,{Z:()=>n});let n=a.p+"assets/images/composable-computing-12f4b6b255fc08bc623ad6aef11fba71.jpg"},16791:function(e,t,a){a.d(t,{Z:()=>n});let n=a.p+"assets/images/pitfalls-of-modern-platform-engineering-4ed789414f7aaf7bad59ca778149cf38.webp"},323:function(e,t,a){a.d(t,{Z:()=>n});let n=a.p+"assets/images/wasmcloudspace-7e7b9520eb26c54b7b5540919f585c4c.webp"},48381:function(e,t,a){a.d(t,{Z:()=>n});let n=a.p+"assets/images/latency-numbers-afc0008c9f618ab231262e161c32ed25.jpg"},50065:function(e,t,a){a.d(t,{Z:()=>r,a:()=>s});var n=a(67294);let o={},i=n.createContext(o);function s(e){let t=n.useContext(i);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(o):e.components||o:s(e.components),n.createElement(i.Provider,{value:t},e.children)}},54743:function(e){e.exports=JSON.parse('{"permalink":"/zh-Hans/blog/2024-12-12-the-pitfalls-of-modern-platform-engineering","source":"@site/blog/2024-12-12-the-pitfalls-of-modern-platform-engineering/index.mdx","title":"The pitfalls of modern platform engineering","description":"Bailey Hayes discusses how WebAssembly and wasmCloud help platform engineering teams tackle the costs and complexities of building and running applications at scale.","date":"2024-12-12T00:00:00.000Z","tags":[],"readingTime":18,"hasTruncateMarker":false,"authors":[{"name":"Bailey Hayes","title":"wasmCloud Maintainer","url":"https://github.com/ricochet","imageURL":"https://github.com/ricochet.png","key":"ricochet","page":null},{"name":"Caroline Tarbett","title":"wasmCloud Maintainer","url":"https://github.com/CazJT","imageURL":"https://github.com/CazJT.png","key":"cazjt","page":null}],"frontMatter":{"title":"The pitfalls of modern platform engineering","authors":["ricochet","cazjt"],"slug":"2024-12-12-the-pitfalls-of-modern-platform-engineering","image":"./images/pitfalls-of-modern-platform-engineering.webp","date":"2024-12-12","description":"Bailey Hayes discusses how WebAssembly and wasmCloud help platform engineering teams tackle the costs and complexities of building and running applications at scale."},"unlisted":false,"prevItem":{"title":"wasmCloud\'s fresh approach to secrets","permalink":"/zh-Hans/blog/2024-12-17-wasmclouds-fresh-approach-to-secrets"},"nextItem":{"title":"Leptos and WASI 0.2 for full stack Wasm development","permalink":"/zh-Hans/blog/2024-12-10-leptos-and-wasi-0.2-for-full-stack-wasm-development"}}')},54997:function(e,t,a){a.d(t,{Z:()=>n});let n=a.p+"assets/images/pitfalls-of-modern-platform-engineering-4ed789414f7aaf7bad59ca778149cf38.webp"},55847:function(e,t,a){a.d(t,{Z:()=>n});let n=a.p+"assets/images/extendable-at-runtime-95c2c5a6e7b84505b048ab18e6dbcdcd.jpeg"},65577:function(e,t,a){a.r(t),a.d(t,{assets:()=>l,contentTitle:()=>r,default:()=>d,frontMatter:()=>s,metadata:()=>n,toc:()=>h});var n=a(54743),o=a(85893),i=a(50065);let s={title:"The pitfalls of modern platform engineering",authors:["ricochet","cazjt"],slug:"2024-12-12-the-pitfalls-of-modern-platform-engineering",image:"./images/pitfalls-of-modern-platform-engineering.webp",date:"2024-12-12",description:"Bailey Hayes discusses how WebAssembly and wasmCloud help platform engineering teams tackle the costs and complexities of building and running applications at scale."},r=void 0,l={image:a(54997).Z,authorsImageUrls:[void 0,void 0]},h=[{value:"Topics covered",id:"topics-covered",level:2},{value:"Transcript",id:"transcript",level:3},{value:"Challenges in modern platform engineering",id:"challenges-in-modern-platform-engineering",level:3},{value:"Introduction to WebAssembly (Wasm) and wasmCloud",id:"introduction-to-webassembly-wasm-and-wasmcloud",level:3},{value:"Benefits of Wasm components and wasmCloud",id:"benefits-of-wasm-components-and-wasmcloud",level:3},{value:"Declarative application manifests and auto-scaling",id:"declarative-application-manifests-and-auto-scaling",level:3},{value:"Polyglot development and composable computing",id:"polyglot-development-and-composable-computing",level:3},{value:"The platform harness pattern",id:"the-platform-harness-pattern",level:3},{value:"Example: Celestial and terrestrial mesh",id:"example-celestial-and-terrestrial-mesh",level:3},{value:"Adoption and future of Wasm",id:"adoption-and-future-of-wasm",level:3}];function c(e){let t={a:"a",code:"code",h2:"h2",h3:"h3",img:"img",li:"li",p:"p",strong:"strong",ul:"ul",...(0,i.a)(),...e.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(t.p,{children:(0,o.jsx)(t.img,{alt:"The Pitfalls of Modern Platform Engineering",src:a(16791).Z+"",width:"1200",height:"630"})}),"\n",(0,o.jsxs)(t.p,{children:["At wasmCloud Innovation Day, we had a chance to ",(0,o.jsx)(t.a,{href:"https://wasmcloud.com/blog/2024-09-24-wasmcloud-innovation-day-2024-in-review",children:"reflect"})," on the state of platform engineering within large companies\u2014and the role WebAssembly has to play in evolving engineering methodologies. We gathered together the wasmCloud community of users, maintainers, and enterprise engineering teams to share advice and best practices when working with WebAssembly in industry."]}),"\n",(0,o.jsx)(t.p,{children:"The recordings are now being uploaded to YouTube, and we wanted to spotlight the most insightful sessions. To set the scene, Cosmonic CTO, Bytecode Alliance TSC director, and Wasm WG co-chair Bailey Hayes\u2019s keynote is a perfect place to start. In her talk she looks at the costs and complexities faced by platform engineering teams building and running applications at scale."}),"\n",(0,o.jsx)("iframe",{width:"560",height:"315",src:"https://www.youtube.com/embed/PexRsU8sVIs",title:"The Pitfalls of Modern Platform Engineering with Bailey Hayes",frameborder:"0",allow:"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share",referrerpolicy:"strict-origin-when-cross-origin",allowfullscreen:!0}),"\n",(0,o.jsxs)(t.p,{children:["Bailey explains how using WebAssembly components as a unit of compute addresses long-standing challenges for platform engineers. Challenges such as the ",(0,o.jsx)(t.strong,{children:"complexity of maintaining application platforms"}),", and the ",(0,o.jsx)(t.strong,{children:"cost of maintaining application code"}),". One great example is the perennial ",(0,o.jsx)(t.strong,{children:"cold start problem"}),". She shows how a containerized application needs multiple containers on the go to address spikes in traffic while meeting standard latency expectations. Since components are able to start in milliseconds rather than the seconds required by containers, components face no such challenges. But the possibilities go further."]}),"\n",(0,o.jsxs)(t.p,{children:["The beauty of components is that they can be ",(0,o.jsx)(t.strong,{children:"composed"})," so that communication between them happens in ",(0,o.jsx)(t.strong,{children:"nanoseconds"}),", rather than being constrained by network communication. Platform engineering teams can compose an application into a larger component that incorporates secrets, authentication, and other requirements that platform teams are on the hook for, giving them a transformative new paradigm."]}),"\n",(0,o.jsx)(t.p,{children:"As just one example of the sort of\xa0composable computing\xa0that can be achieved with wasmCloud, Bailey showcases a demo for a celestial and terrestrial mesh that we're building with a number of different agencies, all interested in running\xa0Wasm in space."}),"\n",(0,o.jsx)(t.p,{children:"As an introduction to both the challenges faced by engineers in a host of sectors, and a comprehensive introduction to wasmCloud and the Wasm Component Model, this talk is unmissable."}),"\n",(0,o.jsxs)(t.p,{children:["Catch the recording above. We\u2019ve also dropped in a handy summary of the topic areas Bailey covers, and you can find the ",(0,o.jsx)(t.strong,{children:"full transcript below"}),". We\u2019d love to hear your thoughts and experiences\u2014find us on ",(0,o.jsx)(t.a,{href:"https://wasmcloud.slack.com/",children:"Slack"})," and join the community."]}),"\n",(0,o.jsx)(t.h2,{id:"topics-covered",children:"Topics covered"}),"\n",(0,o.jsxs)(t.ul,{children:["\n",(0,o.jsxs)(t.li,{children:["\n",(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.a,{href:"/blog/2024-12-12-the-pitfalls-of-modern-platform-engineering#challenges-in-modern-platform-engineering",children:(0,o.jsx)(t.strong,{children:"Challenges in modern platform engineering"})}),": The complexity of maintaining application platforms; the limitations of Kubernetes, the burden of managing open-source dependencies, and the cost of maintaining application code to prevent vulnerabilities."]}),"\n"]}),"\n",(0,o.jsxs)(t.li,{children:["\n",(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.a,{href:"/blog/2024-12-12-the-pitfalls-of-modern-platform-engineering#introduction-to-webassembly-wasm-and-wasmcloud",children:(0,o.jsx)(t.strong,{children:"Introduction to WebAssembly (Wasm) and wasmCloud"})}),": WebAssembly as the new unit of compute; how components compare to containers; and highlighting components' advantages, including how Wasm components are smaller, more secure by default, start in less than a millisecond, and are better suited at the edge."]}),"\n"]}),"\n",(0,o.jsxs)(t.li,{children:["\n",(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.a,{href:"/blog/2024-12-12-the-pitfalls-of-modern-platform-engineering#benefits-of-wasm-components-and-wasmcloud",children:(0,o.jsx)(t.strong,{children:"Benefits of Wasm components and wasmCloud"})}),": How communication between Wasm components can be faster than network requests, allowing for local compute on the edge. Why wasmCloud is the orchestration layer for Wasm applications, allowing the development of applications with composable building blocks, and their deployment across any device, cloud, or edge."]}),"\n"]}),"\n",(0,o.jsxs)(t.li,{children:["\n",(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.a,{href:"/blog/2024-12-12-the-pitfalls-of-modern-platform-engineering#declarative-application-manifests-and-auto-scaling",children:(0,o.jsx)(t.strong,{children:"Declarative application manifests and auto-scaling"})}),": How wasmCloud uses a declarative application manifest similar to Docker Compose, allowing deployment across any device. How it is extendable at runtime and supports auto-scaling, load balancing, and failover, enhancing reliability and fault-tolerance."]}),"\n"]}),"\n",(0,o.jsxs)(t.li,{children:["\n",(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.a,{href:"/blog/2024-12-12-the-pitfalls-of-modern-platform-engineering#polyglot-development-and-composable-computing",children:(0,o.jsx)(t.strong,{children:"Polyglot development and composable computing"})}),": How Wasm components support polyglot development, allowing applications written in different languages to work together. How they are isolated from each other, ensuring security and performance. WIT-defined interfaces and their importance."]}),"\n"]}),"\n",(0,o.jsxs)(t.li,{children:["\n",(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.a,{href:"/blog/2024-12-12-the-pitfalls-of-modern-platform-engineering#the-platform-harness-pattern",children:(0,o.jsx)(t.strong,{children:"The platform harness pattern"})}),": How the platform harness pattern involves building a golden template for all applications. How this approach allows platform teams to manage and maintain a lifecycle separate from application developers. How composable computing enables distributed applications to run efficiently, improving performance and reducing costs."]}),"\n"]}),"\n",(0,o.jsxs)(t.li,{children:["\n",(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.a,{href:"/blog/2024-12-12-the-pitfalls-of-modern-platform-engineering#adoption-and-future-of-wasm",children:(0,o.jsx)(t.strong,{children:"Adoption and future of Wasm"})}),": Where Wasm is already being used in various industries, including serverless edge computing, TVs, cameras, and video distribution. How Wasm is gaining traction in the cloud-native landscape, offering a last plugin model for distributed computing. And, how wasmCloud is the tool for enterprises to adopt Wasm, enabling them to leverage its benefits."]}),"\n"]}),"\n"]}),"\n",(0,o.jsx)(t.h3,{id:"transcript",children:"Transcript"}),"\n",(0,o.jsx)(t.p,{children:(0,o.jsx)(t.strong,{children:"Speakers"})}),"\n",(0,o.jsx)(t.p,{children:"Bailey Hayes, Brooks Townsend"}),"\n",(0,o.jsx)(t.p,{children:(0,o.jsx)(t.strong,{children:"Brooks Townsend"})}),"\n",(0,o.jsx)(t.p,{children:"Without further ado, I'd like to introduce Bailey Hayes, who is a Technical Steering Committee Director at the Bytecode Alliance, WASI sub-group chair, and Cosmonic CTO. Bailey, take it away."}),"\n",(0,o.jsx)(t.p,{children:(0,o.jsx)(t.strong,{children:"Bailey Hayes"})}),"\n",(0,o.jsx)(t.p,{children:"Thank you. Brooks, glad to be here. Really excited to see so many faces joining us for the first time with wasmCloud. I wanted to start the day off by talking about some of the problems that we're looking to solve with wasmCloud, and that begins with some of the pitfalls in modern platform engineering."}),"\n",(0,o.jsx)(t.p,{children:"To start, we need to define platform engineering. So, platform engineering as a practice really began during the containerization era and epoch of compute, where first we started with microservices, bundled those into VMs that allowed us to build out data centers, and eventually moved to the public cloud. But really there was this major paradigm shift that happened when we were able to package our applications into a container and then orchestrate those containers with Kubernetes."}),"\n",(0,o.jsx)(t.p,{children:"That allowed infrastructure teams to evolve to be part of the team that's providing a platform and giving common application services like capabilities from Secrets management to authentication and authorization that then application developers are able to build on top of. Really, this was a massive improvement in our productivity and the types of things that we're able to build, but it does come with some pretty big problems, namely that applications today are just too expensive to build, maintain, and run."}),"\n",(0,o.jsx)(t.h3,{id:"challenges-in-modern-platform-engineering",children:"Challenges in modern platform engineering"}),"\n",(0,o.jsx)(t.p,{children:"That really starts with the initial application language choice, and the template that we build for all of our different apps across enterprises. We are tied into specific clients and frameworks that are part of and built for that language, and we have to maintain these apps on an app-by-app basis. Platform engineering teams are usually on the hook for the application platform layer\u2014that's all of the authentication, observability, maybe even artifact registry, secrets, common storage layer, messaging and more types of capabilities. For the application platform team to be able to evolve their platform\u2014if they are trying to make a new API level change or moving to a new major version\u2014application developers have to update their dependencies."}),"\n",(0,o.jsx)(t.p,{children:"But they're not just revving for being able to evolve the platform. They're revving because most of our application code is not our code. It's full of open source code, which is actually a great thing. It's amazing that we're able to do this, however, that comes with a significant cost and burden on maintaining your application code to prevent vulnerabilities. And so, both by having boilerplate code for your platform and for open source dependencies, we're constantly churning on this application like a hamster wheel of building apps, and we don't really have an easy way to wrangle that problem."}),"\n",(0,o.jsx)(t.p,{children:"Now, on the running and deployment side, platform engineering teams are stuck managing these very expensive platforms. Typically, it's built on top of Kubernetes today\u2014the orchestration layer\u2014and it really lacks portability, because it doesn't allow us to run in many different types of environments, like on the edge. So throughout this platform evolution that we've seen moving through the public era, including containers as part of that era, but that being the major paradigm shift. I believe that today, we are now in a new componentization era, where our next distributed unit of compute is the WebAssembly component, orchestrated by wasmCloud."}),"\n",(0,o.jsx)(t.h3,{id:"introduction-to-webassembly-wasm-and-wasmcloud",children:"Introduction to WebAssembly (Wasm) and wasmCloud"}),"\n",(0,o.jsx)(t.p,{children:"So, let's take a step back and just do a kind of a basic comparison between Wasm and containers. You can think of Wasm as perhaps a tiny VM. So this type of direct comparison works. Okay. Containers themselves are much larger. They're usually on the order of megabytes to gigabytes, whereas a WebAssembly component is kilobytes or megabytes. WebAssembly components themselves are secure by default. For containers, we have to add a number of processes, best practices and tools to get them to a place where they are secure and provide the right level of isolation, but they're still not generally considered the right choice when you're trying to run arbitrary user code, and certainly not on a user's device."}),"\n",(0,o.jsxs)(t.p,{children:["Now the other difference here, while containers give us much more new layers of portability, those images are still CPU architecture-bound, whereas WebAssembly components\u2014the ",(0,o.jsx)(t.code,{children:".wasm"})," file\u2014doesn't need to change for any different environment, so long as that environment has a WebAssembly runtime for it. But perhaps the most important difference between containers and components is that containers start in seconds, whereas WebAssembly components start in less than a millisecond. And that really enables WebAssembly components to solve this major problem that we have in the industry\u2014and that is it solves the cold start problem."]}),"\n",(0,o.jsx)(t.p,{children:"Containers, because they take several seconds to start, they have to effectively keep a pilot light on. They have to keep many different containers running, even though they're not necessarily servicing any requests, because when you get a burst of requests, it takes seconds to scale out, and your response time that a typical user expects is less than a second. So you can't wait on a new container to spin up. Compare that with a WebAssembly component. This list of numbers here, these are numbers that every programmer should know. You've probably seen this set of numbers before, but I think it's really important to highlight where WebAssembly components fit into this latency story."}),"\n",(0,o.jsx)(t.p,{children:(0,o.jsx)(t.img,{alt:"important latency numbers",src:a(48381).Z+"",width:"1199",height:"672"})}),"\n",(0,o.jsx)(t.p,{children:"WebAssembly components, because they start in less than a millisecond, it means that it's so much faster than even making a network request. And so you're going to see new types of architectures evolve because of this new layer that WebAssembly components fit in. Why make a network request to somewhere else when you can be running that compute on the edge next to the user?"}),"\n",(0,o.jsx)(t.h3,{id:"benefits-of-wasm-components-and-wasmcloud",children:"Benefits of Wasm components and wasmCloud"}),"\n",(0,o.jsx)(t.p,{children:"Now, with every new unit of compute, every new thing that we're distributing around, you need a new orchestration layer for that, and that's what wasmCloud is. It's Wasm-native orchestration. It allows you to deploy and manage your Wasm applications across any device, cloud or edge, including your own. When we're building a WebAssembly component, you get a new way of simplifying the way that developers need to build, because you're able to reuse your logic with essentially composable building blocks, and that lets you eliminate boilerplate from your code. wasmCloud lets platform engineers build a component that slots in that the application developers themselves don't have to manage."}),"\n",(0,o.jsx)(t.p,{children:"One thing I really want to highlight here is that Wasm-native also works with cloud native; it has all of the existing cloud native technology integrations that you would expect. A common deployment strategy for wasmCloud actually is to be able to run on Kubernetes and orchestrate your applications with wasmCloud. When we compose applications, we're doing that in wasmCloud with open standards and common interfaces for platform capabilities. These can be swapped at runtime, allowing you to do upgrades for maintenance, or even changing out the vendor entirely. Because these APIs are at a high level, they're vendor-agnostic."}),"\n",(0,o.jsx)(t.p,{children:"We also allow you to write your own custom capabilities and interfaces, and we've had an amazing amount of success\u2014we'll be doing later deep dives on our integrations with Postgres and Couchbase."}),"\n",(0,o.jsx)(t.h3,{id:"declarative-application-manifests-and-auto-scaling",children:"Declarative application manifests and auto-scaling"}),"\n",(0,o.jsx)(t.p,{children:"One thing to understand when we're talking about building apps for wasmCloud is that we have a declarative application manifest. You might later today hear the word \"wadm\"\u2014that's what we're talking about there: the WebAssembly Application Deployment Manifest. And you can just think of that as like a Docker Compose file, but for Wasm. When we run WebAssembly applications in a deployment, we allow you to run that across any device, server, or cloud."}),"\n",(0,o.jsx)(t.p,{children:"This is something that's very, very different from other types of application architectures. It allows you to have a seamless distributed network that automatically load-balances and fails over to available compute. We support vertical and horizontal autoscaling with automatic failover, allowing you to reach this new level of reliability and fault-tolerant applications. Another added benefit here is that we do all of this routing locally first. So, if you're working in one region and there is a type of capability that's closer to you, we route to that first before reaching over across a different region."}),"\n",(0,o.jsx)(t.p,{children:"In this scenario, we're talking about orchestrating Wasm applications. You know that Kubernetes is a container orchestrator, so you can at least think of wasmCloud as Kubernetes, but for Wasm."}),"\n",(0,o.jsx)(t.p,{children:(0,o.jsx)(t.img,{alt:"wasmCloud is extendable at runtime",src:a(55847).Z+"",width:"1200",height:"670"})}),"\n",(0,o.jsx)(t.p,{children:"Another major feature of wasmCloud is that it's extendable at runtime. This is effectively a view of our stack for wasmCloud, where we support WebAssembly components that run in a Wasm sandbox. We have our Wasm host, which embeds a WebAssembly runtime called wasmtime, and then we have many different capability providers that are extendable at runtime."}),"\n",(0,o.jsx)(t.p,{children:"A single WebAssembly component has things that are called imports and exports. These are basically APIs for imports. These are the things that my component needs to run, and my exports are the things that my component provides. So in this case, I may be getting many different secure capabilities that are built into my host. These are often the WASI APIs that you see, and I can also import from extendable capabilities that can be swapped at runtime."}),"\n",(0,o.jsx)(t.p,{children:'Another amazing feature is that WebAssembly components themselves can build on top of each other, just like Lego blocks. And in this case, I can have one component who imports (AKA depends on) another component that exports an interface that it needs to run. So you might be thinking, "Why components? We already have containers. We have had amazing success with containers. So why do we need to go back to the drawing board on our fundamental piece of compute?" And really, I think that part of the problem is the way that we manage.'}),"\n",(0,o.jsx)(t.h3,{id:"polyglot-development-and-composable-computing",children:"Polyglot development and composable computing"}),"\n",(0,o.jsx)(t.p,{children:"With containers, we're bringing in the whole world, whereas with WebAssembly components, we get down to exactly your business logic that is bundled into the app. And when we start back from first principles, we know that we need to use applications that are written in many different languages. We need to be able to support polyglot and so we're able to do that with WebAssembly components, where one component written in Rust and another component written in Go can compose together and communicate over interfaces that are designed so that we can do interface-driven development."}),"\n",(0,o.jsx)(t.p,{children:"And they are also shared nothing leaks, so each component is actually still isolated from each other. Now you would think that, with this level of isolation, there would be this massive performance cost, but that's really not the case, going back to our latency numbers. Now imagine two components that are composed together, in that case, they're actually able to run in the same process, which means when I communicate across that boundary, it happens in nanoseconds. And that is a major difference and a game-changer."}),"\n",(0,o.jsx)(t.p,{children:"Now the way that we define these interfaces is with an IDL called WIT (Wasm Interface Types). It gives us some new capabilities that we don't have in OpenAPI or other IDL-type technologies, and that really comes down to the interface types that we get out of the WebAssembly component model. Namely things like resources and streams that give us the ability to manage the lifetime and lifecycle of components as they're composed together, and in wasmCloud as they're distributed over the network. Later on, Brooks Townsend is going to give a deep dive on how we're able to use resources in a way that solves privacy and security concerns with our secrets."}),"\n",(0,o.jsx)(t.h3,{id:"the-platform-harness-pattern",children:"The platform harness pattern"}),"\n",(0,o.jsx)(t.p,{children:"More than anything, by using WebAssembly components as our primary unit of compute, we can see emerging types of patterns that are going to help platform engineering teams solve major problems that they're experiencing today. And I believe it's with the platform harness pattern. We're seeing that across many different enterprises that are adopting Wasm code, where essentially they're building a golden template that all of their applications are able to compose with so that they create a single component that isolates and I would say, wraps, effectively, all of the different logic that they need to be able to get; their authentication, their secrets. All of the basic things that platform engineering teams are on the hook to provide, but they have the benefit of managing that themselves and maintaining a lifecycle separate from the application developers component that just composes their app."}),"\n",(0,o.jsx)(t.p,{children:"And, once this application component is composed together, you can see that it doesn't expose those imports. It can now just run with the basic standard APIs. So what that gets us to is composable computing that can be distributed across the core in the data center, across edges and clouds, and that's going to be a very powerful change in our industry."}),"\n",(0,o.jsx)(t.p,{children:(0,o.jsx)(t.img,{alt:"composable computing",src:a(10002).Z+"",width:"1200",height:"670"})}),"\n",(0,o.jsx)(t.p,{children:"So to give you a taste of the art of the possible, I'm going to give you a demonstration of a celestial and terrestrial mesh."}),"\n",(0,o.jsx)(t.h3,{id:"example-celestial-and-terrestrial-mesh",children:"Example: Celestial and terrestrial mesh"}),"\n",(0,o.jsx)(t.p,{children:"This is something that we are building in partnership with a number of different agencies that are interested in running WebAssembly in space. What I'm showing here on the screen is a world map with different data centers deployed in Azure and their connectivity over the internet. The job of this application is to identify whether or not something is a boat."}),"\n",(0,o.jsx)(t.p,{children:(0,o.jsx)(t.img,{alt:"boat identification demo",src:a(323).Z+"",width:"1920",height:"1243"})}),"\n",(0,o.jsx)(t.p,{children:"So it's doing image classification. Once I upload an image, imagine some satellite has just taken this photo, and I need to image classify whether or not this was actually a ship. In this case, it decided that it was not a ship."}),"\n",(0,o.jsx)(t.p,{children:"So my prompt engineering here isn't amazing. It's pretty simple. Okay, this one is a ship. Let's do something else. Let's go right back up. Let me give it something that is definitely not a ship. And this is a member of our team. His name is Oscar, and he is not a boat\u2014that is Oscar. And we'll do just one more boat before we're done, just so I can know that here's a boat that one's actually an AI generated boat, but it's real enough for an image classification system. So we'll dive a little bit more into the different pieces and parts that make this app real, from the different capability providers as part of it. But I wanted to go ahead and introduce you to the use case."}),"\n",(0,o.jsx)(t.p,{children:"This is a different view of showing, essentially, that global view that I showed a second ago, where we have a distributed compute mesh. The use cases for this that we're seeing are actively growing, and today's methodologies just can't achieve it. Kubernetes itself and containers are not well suited for running in embedded devices on the edge, whereas WebAssembly is fantastic for that use case, and composing all of this together with the right enterprise-ready security and compliance controls, it makes wasmCloud ready for organizations to adopt."}),"\n",(0,o.jsx)(t.h3,{id:"adoption-and-future-of-wasm",children:"Adoption and future of Wasm"}),"\n",(0,o.jsx)(t.p,{children:"Now, you might be thinking this is new to you, but I just want you to let you know that this technology has actually already won. We're seeing it from Fastly and Cloudflare for serverless edge computing. It's in your TV. It's probably in my camera right now. It is definitely in Zoom that we're running. It is the way that we distribute our videos from Prime Video, Disney Plus, etc. It is taking over the cloud native landscape by storm as being the last plugin model that you'll ever need. So that means that Wasm has taken over the industry, and you're using it everywhere. The future is here. It's just not evenly distributed. So I hope today you'll learn how wasmCloud is the \u2018picks and shovels\u2019 that you need to bring Wasm into your enterprise. Thank you."})]})}function d(e={}){let{wrapper:t}={...(0,i.a)(),...e.components};return t?(0,o.jsx)(t,{...e,children:(0,o.jsx)(c,{...e})}):c(e)}}}]);